// Choose winner
const pool = candidates.filter(n => n !== lastWinner);
const finalPool = pool.length > 0 ? pool : candidates;
const winner = finalPool[Math.floor(Math.random() * finalPool.length)];
const winIdx = candidates.indexOf(winner);
const n = candidates.length;
const slice = 360 / n;
// Target: winner's slice center should be at top (0deg under pointer).
// Slice i center (before rotation) is at angle startA_mid = -90 + i*slice, measured from +x axis (SVG).
// In our drawing, slice i is at i*slice degrees measured from top (clockwise).
// After applying rotation R (CSS rotate clockwise), we want slice winIdx to land at top.
// Top corresponds to rotation where winIdx*slice + R ≡ 0 (mod 360), so R = -winIdx*slice.
// But we spin many turns and add jitter within the slice.
const jitter = (Math.random() - 0.5) * (slice * 0.7);
const totalTurns = 6 + Math.random() * 3; // 6-9 full turns
const finalAngle = totalTurns * 360 - winIdx * slice + jitter;

// Animate with eased deceleration + gust
const duration = 6500 + Math.random() * 1500; // ms
const startTime = performance.now();
const startRot = currentRotation;
const delta = finalAngle - (startRot % 360) + Math.ceil((startRot % 360) / 360) * 360;
// Simpler: set end = startRot + totalTurns*360 adjust to land correctly
const targetRot = startRot + totalTurns * 360 + ((-winIdx * slice + jitter) - (startRot % 360 + 360) % 360 + 360) % 360;

// Gust timing (sudden re-acceleration once)
const gustTime = 0.55 + Math.random() * 0.2; // fraction of duration
const gustApplied = { done: false };

let lastSliceIdx = -1;
let lastTickTime = 0;

return new Promise(resolve => {
  function frame(now) {
    let t = (now - startTime) / duration;
    if (t >= 1) t = 1;

    // Base easing: easeOutCubic-ish but with a gust
    // Piecewise: normal decel until gustTime, then brief boost, then decel to end
    let eased;
    if (t < gustTime) {
      // slightly slower decel in first part
      const localT = t / gustTime;
      eased = (1 - Math.pow(1 - localT, 2)) * 0.65;
    } else {
      const localT = (t - gustTime) / (1 - gustTime);
      // gust: start fast again then ease out
      if (!gustApplied.done) {
        container.classList.add('shake');
        setTimeout(() => container.classList.remove('shake'), 300);
        gustApplied.done = true;
      }
      eased = 0.65 + (1 - Math.pow(1 - localT, 3.5)) * 0.35;
    }

    currentRotation = startRot + (targetRot - startRot) * eased;
    wheelEl.style.transform = `rotate(${currentRotation}deg)`;

    // Tick sound when passing slice boundary
    const normAngle = ((currentRotation % 360) + 360) % 360;
    // Which slice is currently at top?
    // slice at top when winIdx*slice + rot ≡ 0, so current idx = round(-rot/slice) mod n
    const curIdx = ((Math.round(-currentRotation / slice) % n) + n) % n;
    if (curIdx !== lastSliceIdx && (now - lastTickTime) > 30) {
      playBeep(600 + (curIdx * 50), 0.04, 'square');
      lastSliceIdx = curIdx;
      lastTickTime = now;
    }

